/**
 * Badge Service
 * Cấp huy hiệu theo điểm số và độ chuyên cần
 */

const BADGES = {
  FIRST_QUIZ: {
    id: 'first-quiz',
    name: 'Bắt đầu hành trình',
    emoji: '🎯',
    description: 'Hoàn thành bài quiz đầu tiên',
    condition: (stats) => stats.totalQuizzes >= 1,
  },
  PERFECT_SCORE: {
    id: 'perfect-score',
    name: 'Hoàn hảo',
    emoji: '💯',
    description: 'Đạt điểm tuyệt đối 100/100',
    condition: (stats) => stats.perfectScores >= 1,
  },
  STREAK_3: {
    id: 'streak-3',
    name: 'Nóng hổi',
    emoji: '🔥',
    description: 'Làm liên tiếp 3 bài quiz',
    condition: (stats) => stats.currentStreak >= 3,
  },
  STREAK_7: {
    id: 'streak-7',
    name: 'Bất bại',
    emoji: '⚡',
    description: 'Làm liên tiếp 7 bài quiz',
    condition: (stats) => stats.currentStreak >= 7,
  },
  TOTAL_10: {
    id: 'total-10',
    name: 'Chăm chỉ',
    emoji: '📚',
    description: 'Hoàn thành 10 bài quiz',
    condition: (stats) => stats.totalQuizzes >= 10,
  },
  TOTAL_50: {
    id: 'total-50',
    name: 'Siêu sao',
    emoji: '⭐',
    description: 'Hoàn thành 50 bài quiz',
    condition: (stats) => stats.totalQuizzes >= 50,
  },
  HIGH_SCORE: {
    id: 'high-score',
    name: 'Thiên tài',
    emoji: '🧠',
    description: 'Đạt điểm cao nhất 90+',
    condition: (stats) => stats.highestScore >= 90,
  },
};

/**
 * Tính toán thống kê từ lịch sử kết quả
 * @param {Array} results - Mảng các kết quả quiz
 * @returns {Object} Thống kê: { totalQuizzes, perfectScores, currentStreak, highestScore, averageScore }
 */
export const calculateStats = (results) => {
  if (!results || results.length === 0) {
    return {
      totalQuizzes: 0,
      perfectScores: 0,
      currentStreak: 0,
      highestScore: 0,
      averageScore: 0,
    };
  }

  const sortedResults = [...results].sort((a, b) => b.timestamp - a.timestamp);
  const totalQuizzes = results.length;
  const perfectScores = results.filter(r => r.score === 100).length;
  const highestScore = Math.max(...results.map(r => r.score));
  const averageScore = Math.round(
    results.reduce((sum, r) => sum + r.score, 0) / totalQuizzes
  );

  // Tính streak (số bài liên tiếp gần nhất)
  let currentStreak = 0;
  for (const result of sortedResults) {
    if (result.score >= 50) {
      currentStreak++;
    } else {
      break;
    }
  }

  return {
    totalQuizzes,
    perfectScores,
    currentStreak,
    highestScore,
    averageScore,
  };
};

/**
 * Kiểm tra và cấp badge mới dựa trên thống kê
 * @param {Array} results - Mảng các kết quả quiz
 * @param {Array} earnedBadges - Mảng các badge đã có
 * @returns {Array} Mảng các badge mới được cấp
 */
export const checkAndAwardBadges = (results, earnedBadges = []) => {
  const stats = calculateStats(results);
  const earnedBadgeIds = earnedBadges.map(b => b.id);
  const newBadges = [];

  for (const badge of Object.values(BADGES)) {
    // Bỏ qua nếu đã có badge này
    if (earnedBadgeIds.includes(badge.id)) continue;

    // Kiểm tra điều kiện
    if (badge.condition(stats)) {
      newBadges.push({
        ...badge,
        earnedAt: Date.now(),
      });
    }
  }

  return newBadges;
};

/**
 * Lấy tất cả badges
 * @returns {Array} Mảng tất cả badges
 */
export const getAllBadges = () => {
  return Object.values(BADGES);
};

/**
 * Lấy badge theo ID
 * @param {string} badgeId - ID của badge
 * @returns {Object|null} Badge object hoặc null
 */
export const getBadgeById = (badgeId) => {
  return BADGES[badgeId] || Object.values(BADGES).find(b => b.id === badgeId) || null;
};

